// // This module implements a 16-bit shift register that shifts left on the positive edge of the clock and loads the serial input into the least significant bit.
module shift_register_16bit (
    input clk,
    input serial_in,
    output reg [15:0] parallel_out
);

always @(posedge clk) begin
    parallel_out <= {serial_in, parallel_out[15:1]};
end

endmodule
